function extractRaw(itemJson) {
  return itemJson.choices?.[0]?.message?.content
    || itemJson.message?.content
    || itemJson.text
    || itemJson.output
    || '';
}

function parseJson(raw) {
  if (!raw || typeof raw !== 'string') {
    return null;
  }

  let cleaned = raw.trim();

  cleaned = cleaned
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return null;

    try {
      return JSON.parse(match[0]);
    } catch (e2) {
      return null;
    }
  }
}

